arguments.command:
cd /tmp/sv-026e17136698461f816dea63873db219/symbols && \
# The addresses are in .data.rel.ro not .text - so not disassemblable as code
# Let's check if they are actually in .text section
aarch64-linux-gnu-readelf -S libmonosgen-2.0.so.debug | grep -E "\.text|\.data\.rel"
echo "---"
# Check what section 0x2f4b20 belongs to
aarch64-linux-gnu-readelf -S libmonosgen-2.0.so.debug | awk '/\[/ { 
  if (match($0, /\] [^ ]+ +[A-Z]+ +([0-9a-f]+) +[0-9a-f]+ +([0-9a-f]+)/, m)) {
    # not great, lets just find it
  }
}'
# simpler approach
aarch64-linux-gnu-objdump -h libmonosgen-2.0.so.debug | awk '{
  if (NF >= 6 && $2 ~ /^\./) {
    size = strtonum("0x"$3)
    vma = strtonum("0x"$4)
    if (vma <= 0x2f4b20 && vma + size > 0x2f4b20) print "0x2f4b20 in section: "$2, "vma:", $4, "size:", $3
    if (vma <= 0x2f4c84 && vma + size > 0x2f4c84) print "0x2f4c84 in section: "$2, "vma:", $4, "size:", $3
  }
}'

